#include <bits/stdc++.h>
using namespace std;

void printDuplicates(string s) {
    // Sorting method
    sort(s.begin(), s.end());

    for (int i = 0; i < s.length();) {
        int count = 1;

        while (i + count < s.length() && s[i] == s[i + count]) {
            count++;
        }

        if (count > 1) {
            cout << "['" << s[i] << "', " << count << "], ";
        }

        i += count;
    }

    // Hashing method
    unordered_map<char, int> freq;

    for (char c : s) {
        freq[c]++;
    }

    for (auto it : freq) {
        if (it.second > 1) {
            cout << "['" << it.first << "', " << it.second << "], ";
        }
    }
}

int main() {
    string s = "geeksforgeeks";
    printDuplicates(s);
}
